namespace RensaioBackend.Services.Scrobbling;

/// <summary>
/// Provides base64-encoded SVG placeholder icons for scrobbler providers.
/// Each icon is a colored circle with the provider's initial letter.
/// </summary>
internal static class ProviderIcons
{
    // Helper to generate a data URI for an inline SVG icon
    private static string SvgIcon(string letter, string color)
    {
        var svg = $"<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 32 32' width='32' height='32'>"
                + $"<circle cx='16' cy='16' r='15' fill='{color}' />"
                + $"<text x='16' y='21' text-anchor='middle' font-size='13' font-weight='bold' fill='white' font-family='Arial'>{letter}</text>"
                + $"</svg>";
        var base64 = Convert.ToBase64String(System.Text.Encoding.UTF8.GetBytes(svg));
        return $"data:image/svg+xml;base64,{base64}";
    }

    public static string MyAnimeList => "data:image/png;base64,";
    public static string AniList => "data:image/png;base64,";
    public static string ComicVine => "data:image/png;base64,";
    public static string Kitsu => "data:image/png;base64,";
    public static string MangaDex => "data:image/png;base64,";
    public static string Placeholder => SvgIcon("?", "#666666");
}